// Parse monday.com webhook event
const body = $input.first().json.body || $input.first().json;

// monday.com sends a challenge for webhook verification
if (body.challenge) {
  return [{ json: { challenge: body.challenge, isChallenge: true } }];
}

const event = body.event || {};
const pulseId = event.pulseId || event.itemId;
const boardId = event.boardId;
const groupId = event.groupId;
const columnId = event.columnId;
const value = event.value;
const previousValue = event.previousValue;
const eventType = event.type; // e.g., 'update_column_value', 'create_item'

// Map monday.com column IDs to semantic names
const columnMap = {
  'status': 'auditStatus',
  'date4': 'deadline',
  'person': 'assignee',
  'text0': 'contractAddress',
  'dropdown': 'priority',
  'long_text': 'notes',
  'numbers': 'riskScore'
};

return [{
  json: {
    isChallenge: false,
    eventType,
    itemId: pulseId,
    boardId,
    groupId,
    columnId,
    columnName: columnMap[columnId] || columnId,
    newValue: value,
    previousValue,
    timestamp: new Date().toISOString()
  }
}];

