// Build unified audit record from monday.com item
const event = $('Parse monday.com Event').first().json;
const mondayResponse = $input.first().json;
const item = mondayResponse.data?.items?.[0];

if (!item) {
  throw new Error(`Item ${event.itemId} not found in monday.com`);
}

const columns = {};
for (const col of item.column_values || []) {
  columns[col.id] = {
    text: col.text,
    value: col.value ? JSON.parse(col.value) : null
  };
}

const auditRecord = {
  mondayItemId: item.id,
  name: item.name,
  board: item.board?.name,
  group: item.group?.title,
  status: columns.status?.text || 'Unknown',
  contractAddress: columns.text0?.text || null,
  priority: columns.dropdown?.text || 'Medium',
  assignee: columns.person?.text || 'Unassigned',
  deadline: columns.date4?.text || null,
  riskScore: columns.numbers?.text || null,
  notes: columns.long_text?.text || '',
  eventType: event.eventType,
  changedColumn: event.columnName,
  newValue: event.newValue,
  previousValue: event.previousValue,
  updatedAt: event.timestamp
};

return [{ json: auditRecord }];

// Build Telegram notification based on event type
const record = $('Build Audit Record').first().json;

const statusEmoji = {
  'Working on it': '🔄',
  'Done': '✅',
  'Stuck': '🚫',
  'Waiting for review': '⏳',
  'Critical': '🔴',
  'In Progress': '🔄'
};

const emoji = statusEmoji[record.status] || '📋';

let message = '';

switch (record.eventType) {
  case 'update_column_value':
    if (record.changedColumn === 'auditStatus') {
      message = `${emoji} *Audit Status Update*\n\n`;
      message += `📋 *${record.name}*\n`;
      message += `📊 Status: ${record.status}\n`;
      if (record.contractAddress) message += `🔑 Contract: \`${record.contractAddress}\`\n`;
      message += `👤 Assignee: ${record.assignee}\n`;
      if (record.deadline) message += `📅 Deadline: ${record.deadline}\n`;
      if (record.riskScore) message += `⚠️ Risk Score: ${record.riskScore}/100\n`;
    } else {
      message = `📝 *Audit Record Updated*\n\n`;
      message += `📋 *${record.name}*\n`;
      message += `🔄 Changed: ${record.changedColumn}\n`;
      message += `📊 Status: ${record.status}\n`;
    }
    break;
  case 'create_item':
    message = `🆕 *New Audit Created*\n\n`;
    message += `📋 *${record.name}*\n`;
    message += `📂 Board: ${record.board}\n`;
    message += `📁 Group: ${record.group}\n`;
    if (record.contractAddress) message += `🔑 Contract: \`${record.contractAddress}\`\n`;
    break;
  default:
    message = `📋 *Audit Update*\n\n`;
    message += `📋 *${record.name}*\n`;
    message += `📊 Status: ${record.status}\n`;
}

message += `\n🕐 Updated: ${record.updatedAt}`;

return [{ json: { message, record } }];

// Generate daily summary for CRM sync
const record = $('Build Audit Record').first().json;
const syncResult = $('Sync to Internal Systems').first().json;

return [{
  json: {
    event: 'crm_sync_complete',
    itemId: record.mondayItemId,
    itemName: record.name,
    eventType: record.eventType,
    syncStatus: syncResult.success ? 'synced' : 'failed',
    timestamp: new Date().toISOString()
  }
}];
